// ── Success path ──────────────────────────────────────────────────────────
// The orchestrator now returns per-channel breakdown:
//   processed      — total campaigns executed
//   sent           — total messages sent across all channels
//   whatsapp_sent  — messages sent via WhatsApp
//   email_sent     — messages sent via Omnisend email
//   failed         — campaigns that errored
//   campaigns[]    — per-campaign detail { id, name, channel, sent, status }

const data = $input.first().json;

const summary = {
  status: 'success',
  timestamp: new Date().toISOString(),
  campaigns_processed: data.processed || 0,
  total_messages_sent: data.sent || 0,
  whatsapp_sent: data.whatsapp_sent || 0,
  email_sent: data.email_sent || 0,
  campaigns_failed: data.failed || 0,
  campaign_details: (data.campaigns || []).map(c => ({
    name: c.name,
    channel: c.channel,
    sent: c.sent,
    status: c.status
  }))
};

console.log('✅ Campaign automation completed:', JSON.stringify(summary, null, 2));

// Surface a human-readable summary line
summary.message = [
  `Processed ${summary.campaigns_processed} campaign(s).`,
  summary.whatsapp_sent > 0 ? `WhatsApp: ${summary.whatsapp_sent} sent.` : '',
  summary.email_sent > 0   ? `Email (Omnisend): ${summary.email_sent} sent.` : '',
  summary.campaigns_failed > 0 ? `⚠️ ${summary.campaigns_failed} failed.` : ''
].filter(Boolean).join(' ');

return [{ json: summary }];

// Partial failure — some campaigns failed, some succeeded
const data = $input.first().json;
console.warn('⚠️ Partial failure in campaign run:', data.message);
// You can add a Slack / email alert node after this
return [{ json: { ...data, alert: true } }];

// All campaigns succeeded — nothing extra needed
const data = $input.first().json;
console.log('🎉 All campaigns executed cleanly:', data.message);
return [{ json: data }];

// ── Error path ────────────────────────────────────────────────────────────
// The orchestrator returned success=false (HTTP 500 or explicit error body)
const data = $input.first().json;

const errorInfo = {
  status: 'error',
  timestamp: new Date().toISOString(),
  error: data.error || 'Unknown error',
  details: data.details || data.message || '',
  source: data.source || 'n8n_schedule_trigger'
};

console.error('❌ Campaign automation failed:', JSON.stringify(errorInfo, null, 2));

// Throw so N8N marks this execution as failed and triggers error workflow
throw new Error(`Campaign automation failed: ${errorInfo.error}`);
